def find_anagrams(target, words):
    anagrams = []
    sorted_target = sorted(target)

    for word in words:
        if sorted(word) == sorted_target:
            anagrams.append(word)

    return anagrams

class CompressedDataStructure:
    def __init__(self):
        self.data = {}

