def factorial(n, config=None):
    if config is None:
        config = {"depth": 0}  # Default configuration for recursion depth

    if n <= 1:
        return 1
    else:
        config["depth"] += 1  # Incrementing depth with each recursive call
        return n * factorial(n - 1, config)

