    default_config = {
        'case': 'lower',  # sets the standard case preference
        'strip': True,    # indicates whether to trim whitespace
        'remove_special': True  # defines if special characters should be excluded
    }

    normalized = []
    for token in tokens:
        if default_config['strip']:
            token = token.strip()
        if default_config['case'] == 'lower':
            token = token.lower()
        if default_config['remove_special']:

